javascript:(function() {
    if (window.NativeSocketRegistry) return;

    const OriginalBrowserWebSocket = window.WebSocket;
    const socketInstances = new Map();

    window.NativeSocketRegistry = {
        triggerMessage: function(socketId, payload) {
            const clientSocket = socketInstances.get(socketId);
            if (clientSocket && typeof clientSocket.onmessage === 'function') {
                clientSocket.onmessage({ data: payload, target: clientSocket });
            }
        }
    };

    // The new constructor wrapper
    window.WebSocket = function(url, protocols) {
        const isLocalFakeRoute = url.includes('virtual-local-bridge') || url.startsWith('ws://decabase.com') || url.includes('/api/ws/');

        if (!isLocalFakeRoute) {
            console.log('[WS_ROUTER] Routing to Standard Browser Web-Stack: ' + url);
            return new OriginalBrowserWebSocket(url, protocols);
        }

        console.log('[WS_ROUTER] Intercepting to Native JVM Architecture: ' + url);

        // Expose standard browser API state properties natively
        this.url = url;
        this.readyState = 0; // CONNECTING
        this.extensions = '';
        this.protocol = '';
        this.binaryType = 'blob';

        // Set up callback hooks explicitly to avoid signature tracking misses
        this.onopen = null;
        this.onmessage = null;
        this.onerror = null;
        this.onclose = null;

        this._id = Math.random().toString(36).substring(2, 11) + String(Date.now());

        const parser = document.createElement('a');
        parser.href = url;
        const routePath = parser.pathname;

        socketInstances.set(this._id, this);

        if (window.AndroidWebSocketBridge) {
            window.AndroidWebSocketBridge.connectNative(this._id, routePath);
        }

        setTimeout(() => {
            this.readyState = 1; // OPEN
            if (typeof this.onopen === 'function') this.onopen();
        }, 15);

        this.send = function(data) {
            if (this.readyState !== 1) {
                throw new Error('InvalidStateError: The connection is not in an OPEN state.');
            }
            if (window.AndroidWebSocketBridge) {
                let serialized = typeof data === 'string' ? data : JSON.stringify(data);
                window.AndroidWebSocketBridge.sendNative(this._id, serialized);
            }
        };

        this.close = function() {
            if (this.readyState === 3) return;
            this.readyState = 3; // CLOSED
            if (window.AndroidWebSocketBridge) {
                window.AndroidWebSocketBridge.closeNative(this._id);
            }
            socketInstances.delete(this._id);
            if (typeof this.onclose === 'function') this.onclose();
        };
    };

    // Completely isolate the prototype chain from the native C++ browser bindings
    window.WebSocket.prototype = Object.create(Object.prototype);
    window.WebSocket.prototype.constructor = window.WebSocket;
})();

javascript:(function() {
    if (window.HasAndroidFetchIntercepted) return;
    window.HasAndroidFetchIntercepted = true;

    const originalFetch = window.fetch;
    window.fetch = function(input, init) {
        let targetUrl = '';
        let requestConfig = init || {};

        if (typeof input === 'string') {
            targetUrl = input;
        } else if (input instanceof URL) {
            targetUrl = input.href;
        } else if (input && typeof input.url === 'string') {
            targetUrl = input.url;
            if (!init) { requestConfig = input; }
        }

        const method = (requestConfig.method || 'GET').toUpperCase();
        const validMutations = ['POST', 'PUT', 'PATCH', 'DELETE'];

        if (requestConfig.body && validMutations.includes(method)) {
            // Telemetry Point 1: Calculate serialization cost inside JavaScript
            const startSerialization = performance.now();
            let payloadString = typeof requestConfig.body === 'string' 
                ? requestConfig.body 
                : JSON.stringify(requestConfig.body);
            const endSerialization = performance.now();

            if (window.AndroidBridge && typeof window.AndroidBridge.captureRequestBody === 'function') {
                const jsTimestampStr = String(Date.now());

                // Inject serialization stats into console logcat implicitly
                console.log('[TELEMETRY_JS] Route: ' + method + ':' + targetUrl + ' | Stringify Duration: ' + (endSerialization - startSerialization).toFixed(4) + 'ms');

                window.AndroidBridge.captureRequestBody(method, targetUrl, payloadString, jsTimestampStr);
            }
        }
        return originalFetch.apply(this, arguments);
    };

    const originalOpen = XMLHttpRequest.prototype.open;
    XMLHttpRequest.prototype.open = function(method, url) {
        this._method = method ? method.toUpperCase() : 'GET';
        this._url = url;
        return originalOpen.apply(this, arguments);
    };

    const originalSend = XMLHttpRequest.prototype.send;
    XMLHttpRequest.prototype.send = function(body) {
        const validMutations = ['POST', 'PUT', 'PATCH', 'DELETE'];
        if (body && validMutations.includes(this._method) && typeof this._url === 'string') {
            const startSerialization = performance.now();
            let payloadString = typeof body === 'string' ? body : JSON.stringify(body);
            const endSerialization = performance.now();

            if (window.AndroidBridge && typeof window.AndroidBridge.captureRequestBody === 'function') {
                console.log('[TELEMETRY_JS_AJAX] Route: ' + this._method + ':' + this._url + ' | Stringify Duration: ' + (endSerialization - startSerialization).toFixed(4) + 'ms');
                window.AndroidBridge.captureRequestBody(this._method, this._url, payloadString, String(Date.now()));
            }
        }
        return originalSend.apply(this, arguments);
    };
})();
